// Modelo de datos del modulo de Finanzas — Avisos de Pago Automaticos (GAP-FIN-004).

/** Estado de un aviso ya registrado en el historial. */
export type AvisoEstado = 'enviado' | 'error' | 'sin_correo';

/** Estado del aviso asociado a un egreso del ERP. */
export type EgresoAviso = 'pendiente' | 'enviado' | 'error' | 'sin_correo';

/** Proveedor sincronizado con el ERP. Solo el correo de avisos y el contacto son configurables. */
export interface Proveedor {
	id: number;
	rfc: string;
	nombre: string;
	/** Correo comercial proveniente del ERP (solo lectura). */
	correoC: string;
	/** Correo para avisos de pago (configurable en el portal). */
	correoA: string;
	contacto: string;
	tel: string;
	/** Si los avisos automaticos estan activos para este proveedor. */
	activo: boolean;
}

/** Una factura liquidada dentro de un egreso. */
export interface Factura {
	num: string;
	desc: string;
	sub: number;
	iva: number;
	tot: number;
	/** Saldo restante por liquidar en un siguiente ciclo (opcional). */
	saldoRest?: number;
}

/** Un egreso generado en el ERP, candidato a enviar aviso al proveedor. */
export interface Egreso {
	id: string;
	fecha: string; // 'YYYY-MM-DD'
	provId: number;
	facturas: Factura[];
	monto: number;
	ref: string;
	banco: string;
	aviso: EgresoAviso;
}

/** Registro de un aviso enviado (o intentado). */
export interface HistorialAviso {
	id: number;
	fecha: string; // 'YYYY-MM-DD HH:mm:ss'
	provId: number;
	facturas: Factura[];
	monto: number;
	correo: string;
	ref: string;
	banco: string;
	estado: AvisoEstado;
}

/** Preferencias generales del envio de avisos. */
export interface FinanzasConfig {
	envioAutomatico: boolean;
	reintentar: boolean;
	notificarErrores: boolean;
	retencionDias: number;
}

export interface FinanzasState {
	proveedores: Proveedor[];
	egresos: Egreso[];
	historial: HistorialAviso[];
	config: FinanzasConfig;
	nextHistId: number;
	lastUpdated: string;
}

import type { AvisoEstado, EgresoAviso } from './types';

// --- Datos del emisor usados en el aviso de pago (correo al proveedor). ---
export const EMPRESA = {
	nombre: 'TPS Intelisis',
	remitente: 'Tesorería TPS',
	correoRemitente: 'notificaciones.finanzas@empresa.com.mx',
	cc: 'cxp@empresa.com.mx',
	tel: '55-1234-5678',
	correo: 'finanzas@empresa.com.mx'
};

// --- Estados del historial ---
export const AVISO_ESTADO_LABELS: Record<AvisoEstado, string> = {
	enviado: 'Enviado',
	error: 'Error',
	sin_correo: 'Sin correo'
};

// Paleta alineada al tema: emerald para exito, destructive para error, chart-4 para advertencia.
export const AVISO_ESTADO_COLORS: Record<AvisoEstado, string> = {
	enviado: 'bg-emerald-500/15 text-emerald-400',
	error: 'bg-destructive/15 text-destructive',
	sin_correo: 'bg-chart-4/15 text-chart-4'
};

// --- Estados del aviso de un egreso ERP ---
export const EGRESO_AVISO_LABELS: Record<EgresoAviso, string> = {
	pendiente: 'Pendiente',
	enviado: 'Enviado',
	error: 'Error',
	sin_correo: 'Sin correo'
};

export const EGRESO_AVISO_COLORS: Record<EgresoAviso, string> = {
	pendiente: 'bg-chart-3/20 text-chart-3',
	enviado: 'bg-emerald-500/15 text-emerald-400',
	error: 'bg-destructive/15 text-destructive',
	sin_correo: 'bg-chart-4/15 text-chart-4'
};

/** Formato de moneda ($ es-MX, 2 decimales), identico al del resto del ERP. */
export function fmtMoney(n: number): string {
	return '$' + n.toLocaleString('es-MX', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

/** Version compacta para KPIs (millones abreviados). */
export function fmtMoneyShort(n: number): string {
	if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(2)}M`;
	return fmtMoney(n);
}

/** Valida un correo electronico de forma sencilla. */
export function isValidEmail(email: string): boolean {
	return /\S+@\S+\.\S+/.test(email);
}

