		this.#commit();
	}

	// --- Configuracion ---
	updateConfig(updates: Partial<FinanzasConfig>) {
		this.state.config = { ...this.state.config, ...updates };
		this.#commit();
	}

	resetData() {
		this.state = createInitialFinanzasState();
		if (browser) localStorage.removeItem(STORAGE_KEY);
		this.#commit();
	}
}

