	VEHICULOS,
	DOCUMENTOS_OBLIGATORIOS,
	LISTA_NEGRA,
	FLOW_STEPS,
	todayISO,
	nowStr
} from './constants';

const STORAGE_KEY = 'tps-rentas-state';
const DATA_VERSION = 1;

function loadState(): RentasState | null {
	if (!browser) return null;
	try {
		const raw = localStorage.getItem(STORAGE_KEY);
		if (!raw) return null;
